<#
.SYNOPSIS
    addclip
#>
New-Item -Path "HKCU:\Software\Microsoft\Clipboard" -Force -ErrorAction SilentlyContinue; Set-ItemProperty -Path "HKCU:\Software\Microsoft\Clipboard" -Name "EnableClipboardHistory" -Value 1 -Type DWord -Force; reg add "HKCU\Software\Microsoft\Clipboard" /v EnableClipboardHistory /t REG_DWORD /d 1 /f; New-Item -Path "HKLM:\SOFTWARE\Policies\Microsoft\Windows\System" -Force -ErrorAction SilentlyContinue; Set-ItemProperty -Path "HKLM:\SOFTWARE\Policies\Microsoft\Windows\System" -Name "AllowClipboardHistory" -Value 1 -Type DWord -Force -ErrorAction SilentlyContinue; reg add "HKLM\SOFTWARE\Policies\Microsoft\Windows\System" /v AllowClipboardHistory /t REG_DWORD /d 1 /f; gpupdate /force; $clipboardService = Get-Service -Name "cbdhsvc*" -ErrorAction SilentlyContinue; if($clipboardService){Set-Service -Name $clipboardService.Name -StartupType Automatic -ErrorAction SilentlyContinue; Start-Service -Name $clipboardService.Name -ErrorAction SilentlyContinue}; Get-Service -Name "cbdhsvc*" | Set-Service -StartupType Automatic -ErrorAction SilentlyContinue; Get-Service -Name "cbdhsvc*" | Start-Service -ErrorAction SilentlyContinue; Add-Type -AssemblyName System.Windows.Forms; [System.Windows.Forms.Clipboard]::SetText("Clipboard history test"); Stop-Process -Name explorer -Force; Start-Sleep -Seconds 2; Start-Process explorer; Start-Sleep -Seconds 1; Start-Process "ms-settings:clipboard"
